terraform_example.snippet:
resource "cloudflare_ruleset" "xxe_baseline" {
  zone_id = var.zone_id
  name    = "XXE Detection Baseline"
  kind    = "zone"
  phase   = "http_request_firewall_custom"

  rules {
    description = "Detect XML DTD/entity declarations"
    expression  = "(http.request.body.raw contains \"<!DOCTYPE\") or (http.request.body.raw contains \"<!ENTITY\")"
    action      = "log"
    enabled     = true
  }

  rules {
    description = "Detect file:// and expect:// XXE indicators"
    expression  = "(http.request.body.raw contains \"file://\") or (http.request.body.raw contains \"expect://\")"
    action      = "managed_challenge"
    enabled     = true
  }
}
